 51→suspend fun handleCollectionPostRequest(methodName: String, bytes: ByteArray): ByteArray? {
 52→    return when (methodName) {
 53→        "i18nResources" -> withCol { i18nResourcesRaw(bytes) }
 54→        "getGraphPreferences" -> withCol { getGraphPreferencesRaw() }
 55→        "setGraphPreferences" -> withCol { setGraphPreferencesRaw(bytes) }
 56→        "graphs" -> withCol { graphsRaw(bytes) }
 57→        "getNotetypeNames" -> withCol { getNotetypeNamesRaw(bytes) }
