 59→        "getCsvMetadata" -> withCol { getCsvMetadataRaw(bytes) }
 60→        "importCsv" -> importCsvRaw(bytes)
 61→        "importAnkiPackage" -> importAnkiPackageUndoable(bytes)
 62→        "importDone" -> bytes
 63→        "getImportAnkiPackagePresets" -> withCol { getImportAnkiPackagePresetsRaw(bytes) }
 64→        "completeTag" -> withCol { completeTagRaw(bytes) }
 65→        "getFieldNames" -> withCol { getFieldNamesRaw(bytes) }
 66→        "cardStats" -> withCol { cardStatsRaw(bytes) }
 67→        "getDeckConfig" -> withCol { getDeckConfigRaw(bytes) }
 68→        "getDeckConfigsForUpdate" -> withCol { getDeckConfigsForUpdateRaw(bytes) }
 69→        "computeFsrsWeights" -> withCol { computeFsrsWeightsRaw(bytes) }
 70→        "computeOptimalRetention" -> withCol { computeOptimalRetentionRaw(bytes) }
 71→        "evaluateWeights" -> withCol { evaluateWeightsRaw(bytes) }
 72→        "getImageForOcclusion" -> withCol { getImageForOcclusionRaw(bytes) }
 73→        "getImageOcclusionNote" -> withCol { getImageOcclusionNoteRaw(bytes) }
 74→        "getImageForOcclusionFields" -> withCol { getImageOcclusionFieldsRaw(bytes) }
 75→        "setWantsAbort" -> getBackend().setWantsAbortRaw(bytes)
 76→        "latestProgress" -> getBackend().latestProgressRaw(bytes)
 77→        "congratsInfo" -> withCol { congratsInfoRaw(bytes) }
 78→        else -> null
 79→    }
 80→}
 81→
 82→suspend fun FragmentActivity?.handleUiPostRequest(methodName: String, bytes: ByteArray): ByteArray? {
 83→    if (this == null) {
 84→        Timber.w("ignored UI request '%s' due to screen/app being backgrounded", methodName)
 85→        return null
 86→    }
 87→    return when (methodName) {
 88→        "searchInBrowser" -> searchInBrowser(bytes)
 89→        "updateDeckConfigs" -> updateDeckConfigsRaw(bytes)
 90→        "addImageOcclusionNote" -> {
 91→            val data = withCol { addImageOcclusionNoteRaw(bytes) }
 92→            undoableOp { OpChanges.parseFrom(data) }
 93→            launchCatchingTask {
 94→                // Allow time for toast message to appear before closing editor
 95→                delay(1000)
 96→                setResult(Activity.RESULT_OK)
 97→                finish()
 98→            }
 99→            data
100→        }
101→        "updateImageOcclusionNote" -> {
102→            val data = withCol {
103→                updateImageOcclusionNoteRaw(bytes)
104→            }
105→            undoableOp { OpChanges.parseFrom(data) }
106→            launchCatchingTask {
107→                // Allow time for toast message to appear before closing editor
108→                delay(1000)
109→                setResult(NoteEditor.RESULT_UPDATED_IO_NOTE)
110→                finish()
111→            }
112→            data
113→        }
114→        else -> null
115→    }
116→}
