     * Inject the HTTP server URL into the HTML content so that JavaScript API calls
     * can use absolute URLs to communicate with the server while media files are served via file://
     */
    private fun injectServerUrlIntoContent(content: String): String {
        val serverUrl = server.baseUrl()
        val serverUrlScript = """
            <script>
                // Configure AnkiDroid API server URL for CORS-free communication
                window.ankidroidServerUrl = '$serverUrl';

                // Function to override handleRequest when AnkiDroidJS is available
                function overrideAnkiDroidJS() {
                    if (typeof AnkiDroidJS !== 'undefined' && AnkiDroidJS.prototype.handleRequest) {
                        AnkiDroidJS.prototype.handleRequest = async function(endpoint, data) {
                            const url = window.ankidroidServerUrl + 'jsapi/' + endpoint;
                            try {
                                const response = await fetch(url, {
                                    method: "POST",
                                    headers: {
                                        "Content-Type": "application/json",
                                    },
                                    body: JSON.stringify({
                                        developer: this.developer,
                                        version: this.version,
                                        data,
                                    }),
                                });

                                if (!response.ok) {
                                    throw new Error("Failed to make the request");
                                }

                                const responseData = await response.text();
                                if (endpoint.includes("nextTime") || endpoint.includes("deckName")) {
                                    return responseData;
                                }
                                return JSON.parse(responseData);
                            } catch (error) {
                                console.error("Request error:", error);
                                throw error;
                            }
                        };
                        return true;
                    }
                    return false;
                }

                // Try to override immediately
                if (!overrideAnkiDroidJS()) {
                    // If not available yet, try again when DOM is loaded
                    if (document.readyState === 'loading') {
                        document.addEventListener('DOMContentLoaded', overrideAnkiDroidJS);
                    } else {
                        // Try again after a short delay
                        setTimeout(overrideAnkiDroidJS, 100);
                    }
                }
            </script>
        """.trimIndent()

        // Inject the script before the closing head tag, or before the closing body tag as fallback
        return when {
            content.contains("</head>") -> content.replace("</head>", "$serverUrlScript\n</head>")
            content.contains("</body>") -> content.replace("</body>", "$serverUrlScript\n</body>")
            else -> content + serverUrlScript
        }
    }"}

